import { type AnimationLibs, initAnimationLibs } from '@lib/animations/animation-libs';
import { initAnchorLinks, resetScroll } from '@lib/animations/scroll';
import { createTimeline, type Timeline } from '@lib/animations/section-timeline';
import { createSection1, fadeInHeader1 } from './sections/section-1';

type Store = {
  timeline: Timeline;
};

let lastTime = 0;
let store: Store | null = null;
const STORIES_TAB_SESSION_KEY = 'stories:selected-tab';
const TAB_FADE_DURATION_MS = 1060;
const TAB_FADE_Y_OFFSET_PX = 16;

function initTimeline(libs: AnimationLibs) {
  const timeline = createTimeline(libs);
  timeline.initSection(createSection1(libs, {}));
  timeline.refresh();
  return timeline;
}

function initLenisOverlayListener(libs: AnimationLibs) {
  document.addEventListener('video-player:lenis', ((e: CustomEvent<{ action: string }>) => {
    if (e.detail.action === 'stop') libs.lenis.stop();
    else if (e.detail.action === 'start') libs.lenis.start();
  }) as EventListener);
}

function initCleanupListener() {
  document.addEventListener('astro:before-swap', () => {
    if (!store) return;
    store.timeline.dispose();
    store = null;
  });
}

function initAnimations() {
  const animate = (currentTime: number) => {
    if (!store) return;
    requestAnimationFrame(animate);
    // const deltaTime = currentTime - lastTime;
    lastTime = currentTime;
  };
  lastTime = performance.now();
  animate(lastTime);
}

export function initTabs() {
  const tabsRoot = document.getElementById('tabs');
  const panelsRoot = document.getElementById('panels');
  if (!tabsRoot || !panelsRoot) return;
  const tabs = Array.from(tabsRoot.querySelectorAll('button[role="tab"]')) as HTMLButtonElement[];
  const panels = Array.from(panelsRoot.querySelectorAll<HTMLElement>('[role="tabpanel"]'));
  const panelAnimations = new WeakMap<HTMLElement, Animation>();
  let hasSetInitialSelection = false;
  if (tabs.length === 0 || panels.length === 0) return;
  const shouldReduceMotion = () => window.matchMedia('(prefers-reduced-motion: reduce)').matches;
  const animatePanelIn = (panel: HTMLElement) => {
    if (shouldReduceMotion()) return;
    panelAnimations.get(panel)?.cancel();
    const animation = panel.animate(
      [
        {
          opacity: 0,
          filter: 'brightness(0)',
          transform: `translateY(${TAB_FADE_Y_OFFSET_PX}px)`
        },
        { opacity: 1, filter: 'brightness(1)', transform: 'translateY(0)' }
      ],
      { duration: TAB_FADE_DURATION_MS, easing: 'cubic-bezier(0.22, 1, 0.36, 1)', fill: 'both' }
    );
    panelAnimations.set(panel, animation);
  };
  const getSavedTabId = () => {
    try {
      return sessionStorage.getItem(STORIES_TAB_SESSION_KEY);
    } catch {
      return null;
    }
  };
  const saveTabId = (tabId: string) => {
    try {
      sessionStorage.setItem(STORIES_TAB_SESSION_KEY, tabId);
    } catch {
      // no-op when sessionStorage is unavailable
    }
  };
  const setSelected = (nextIndex: number, shouldAnimate = true) => {
    const currentIndex = getCurrentIndex();
    if (hasSetInitialSelection && currentIndex === nextIndex) return;
    tabs.forEach((tab, i) => {
      const isSelected = i === nextIndex;
      tab.setAttribute('aria-selected', isSelected ? 'true' : 'false');
      if (isSelected) tab.removeAttribute('tabindex');
      else tab.setAttribute('tabindex', '-1');
      tab.parentElement?.classList.toggle('is-selected', isSelected);
    });
    panels.forEach((panel, i) => {
      panel.hidden = i !== nextIndex;
    });
    if (shouldAnimate) {
      const selectedPanel = panels[nextIndex];
      if (selectedPanel) animatePanelIn(selectedPanel);
    }
    const selectedTab = tabs[nextIndex];
    if (selectedTab?.id) saveTabId(selectedTab.id);
    hasSetInitialSelection = true;
  };
  const getCurrentIndex = () => tabs.findIndex(t => t.getAttribute('aria-selected') === 'true');
  const savedTabId = getSavedTabId();
  const savedIndex = savedTabId ? tabs.findIndex(tab => tab.id === savedTabId) : -1;
  const initialIndex = savedIndex >= 0 ? savedIndex : getCurrentIndex();
  setSelected(initialIndex >= 0 ? initialIndex : 0, false);
  tabs.forEach((tab, i) => {
    tab.addEventListener('click', () => setSelected(i));
    tab.addEventListener('keydown', (e: KeyboardEvent) => {
      const currentIndex = getCurrentIndex();
      if (currentIndex < 0) return;
      const { key } = e;
      if (key !== 'ArrowLeft' && key !== 'ArrowRight' && key !== 'Home' && key !== 'End') return;
      e.preventDefault();
      let nextIndex = currentIndex;
      if (key === 'ArrowLeft') nextIndex = Math.max(0, currentIndex - 1);
      if (key === 'ArrowRight') nextIndex = Math.min(tabs.length - 1, currentIndex + 1);
      if (key === 'Home') nextIndex = 0;
      if (key === 'End') nextIndex = tabs.length - 1;
      setSelected(nextIndex);
      tabs[nextIndex]?.focus();
    });
  });
}

async function init() {
  resetScroll();
  // Initialize the selected panel before loading animation libs so hidden tab content
  // does not compete with the above-the-fold render.
  initTabs();
  const libs = await initAnimationLibs();
  const timeline = initTimeline(libs);
  store = { timeline };
  initLenisOverlayListener(libs);
  initCleanupListener();
  initAnimations();
  fadeInHeader1(libs);
  initAnchorLinks(libs);
}

init();
